mapper.sql:
from chat_conversation c left join ( select conversation_id, count(1) as member_count from chat_conversation_member where status = 1 group by conversation_id ) member_stats on member_stats.conversation_id = c.id left join chat_conversation_member cm_self on cm_self.conversation_id = c.id and cm_self.user_id = #{userId} and cm_self.status = 1 where c.conversation_type = 'group' and c.is_all_site = 0 and c.status = 1 and c.visibility_scope = 'public'
and ( c.name like concat('%', #{keyword}, '%') or c.remark like concat('%', #{keyword}, '%') )
and c.channel_category_code = #{categoryCode}

from chat_conversation c
left join (
select conversation_id, count(1) as member_count
from chat_conversation_member
where status = 1
group by conversation_id
) member_stats
on member_stats.conversation_id = c.id
left join chat_message lm
on lm.id = c.last_message_id
where 1 = 1

    and (
    c.name like concat('%', #{query.keyword}, '%')
    or lm.content like concat('%', #{query.keyword}, '%')
    )


    and c.conversation_type = #{query.conversationType}


    and c.status = #{query.status}


    and c.owner_id = #{query.ownerId}


    and exists (
    select 1
    from chat_conversation_member cm_filter
    where cm_filter.conversation_id = c.id
    and cm_filter.user_id = #{query.memberUserId}
    )


    and c.is_all_site = #{query.isAllSite}
